import json
import boto3
import os

sns_client = boto3.client('sns')

def lambda_handler(event, context):
    message = event.get('message')
    topic_arn = event.get('topic_arn')
    notification_type = event.get('notification_type', 'default')

    if not message or not topic_arn:
        return {
            'statusCode': 400,
            'body': json.dumps('Message and topic ARN are required.')
        }

    # Validate the topic ARN format
    if not validate_topic_arn(topic_arn):
        return {
            'statusCode': 400,
            'body': json.dumps('Invalid topic ARN format.')
        }

    try:
        response = sns_client.publish(
            TopicArn=topic_arn,
            Message=json.dumps({'default': message}),
            MessageStructure='json'
        )
        return {
            'statusCode': 200,
            'body': json.dumps('Message published successfully.')
        }
    except Exception as e:
        return {
            'statusCode': 500,
            'body': json.dumps(f'Error publishing message: {str(e)}')
        }

def validate_topic_arn(topic_arn):
    # Basic validation for ARN format
    return isinstance(topic_arn, str) and topic_arn.startswith('arn:aws:sns:')